const STEP_LABELS = ['첫 답변', '1차 피드백', '업그레이드', '최종 피드백', '꼬리질문']

const MicBtn = ({ recording, onClick }: { recording: boolean; onClick: () => void }) => (
  <button onClick={onClick}
    style={{ width: 36, height: 36, background: recording ? '#FEE2E2' : '#EEF2FF', color: recording ? '#EF4444' : '#3B5BDB', border: `0.5px solid ${recording ? '#FCA5A5' : '#BAC8FF'}`, borderRadius: 7, fontSize: 15, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
    {recording ? '⏹' : '🎙️'}
  </button>
)

const SubmitBtn = ({ label, onClick, disabled }: { label: string; onClick: () => void; disabled: boolean }) => (
  <button onClick={onClick} disabled={disabled}
    style={{ height: 36, padding: '0 16px', background: !disabled ? '#3B5BDB' : '#E5E7EB', color: !disabled ? '#fff' : '#9CA3AF', border: 'none', borderRadius: 7, fontSize: 12, fontWeight: 500, cursor: !disabled ? 'pointer' : 'not-allowed', fontFamily: 'inherit', flexShrink: 0 }}>
    {label}
  </button>
)

export default function Presentation() {
  const [step, setStep] = useState<'school' | 'list' | 'solve'>('school')
  const [selSchool, setSelSchool] = useState<any>(null)
  const [selTrack, setSelTrack] = useState<any>(null)
  const [selYear, setSelYear] = useState(2025)
  const [selProblem, setSelProblem] = useState<any>(null)
  const [showTrackModal, setShowTrackModal] = useState(false)
  const [showEduModal, setShowEduModal] = useState(false)
  const [problems, setProblems] = useState(PROBLEMS)

  const [answers, setAnswers] = useState<Record<string, string>>({})
  const [upgradedAnswers, setUpgradedAnswers] = useState<Record<string, string>>({})
  const [tailAnswers, setTailAnswers] = useState<Record<string, string>>({})
  const [recordings, setRecordings] = useState<Record<string, boolean>>({})
  const [editingStep1, setEditingStep1] = useState<Record<string, boolean>>({})
  const [editingStep3, setEditingStep3] = useState<Record<string, boolean>>({})
  const [openIntents, setOpenIntents] = useState<Record<string, boolean>>({})

  const [leftWidth, setLeftWidth] = useState(50)
  const isDragging = useRef(false)
  const containerRef = useRef<HTMLDivElement>(null)

  const isEdu = selSchool?.type === 'edu'
  const accentColor = isEdu ? '#059669' : '#3B5BDB'
  const accentBg = isEdu ? '#ECFDF5' : '#EEF2FF'
  const accentBorder = isEdu ? '#6EE7B7' : '#BAC8FF'

  const problemKey = selSchool
    ? isEdu ? `${selSchool.id}-${selYear}`
    : selTrack ? `${selSchool.id}-${selTrack.id}-${selYear}` : ''
    : ''
  const curProblems = problems[problemKey] || []

  const handleDragStart = useCallback(() => { isDragging.current = true }, [])
  const handleDragEnd = useCallback(() => { isDragging.current = false }, [])
  const handleDragMove = useCallback((e: React.MouseEvent) => {
    if (!isDragging.current || !containerRef.current) return
    const rect = containerRef.current.getBoundingClientRect()
    const pct = ((e.clientX - rect.left) / rect.width) * 100
    setLeftWidth(Math.min(75, Math.max(25, pct)))
  }, [])

  const getProblemStatus = (p: any) => {
    const all = p.questions.every((q: any) => q.answer)
    if (all) return 'done'
    const any = p.questions.some((q: any) => q.answer)
    if (any) return 'doing'
    return 'new'
  }

  const getQStep = (q: any) => {
    if (!q.answer) return 1
    if (!q.teacherFeedback) return 2
    if (!q.upgradedAnswer) return 3
    if (!q.finalFeedback) return 4
    return 5
  }

  const updateQuestion = (problemId: number, questionId: number, patch: any) => {
    const updated = { ...problems }
    updated[problemKey] = updated[problemKey].map((p: any) =>
      p.id === problemId
        ? { ...p, questions: p.questions.map((q: any) => q.id === questionId ? { ...q, ...patch } : q) }
        : p
    )
    setProblems(updated)
    if (selProblem?.id === problemId) {
      setSelProblem((prev: any) => ({
        ...prev,
        questions: prev.questions.map((q: any) => q.id === questionId ? { ...q, ...patch } : q)
      }))
    }
  }

  const submitAnswer = (problemId: number, q: any) => {
    const key = `${problemId}-${q.id}`
    const val = answers[key] || ''
    if (!val.trim()) return
    updateQuestion(problemId, q.id, { answer: val, teacherFeedback: '', upgradedAnswer: '', finalFeedback: '', tails: [] })
    setAnswers(p => ({ ...p, [key]: '' }))
    setEditingStep1(p => ({ ...p, [key]: false }))
    setRecordings(p => ({ ...p, [key]: false }))
  }

  const submitUpgrade = (problemId: number, q: any) => {
    const key = `${problemId}-${q.id}`
    const val = upgradedAnswers[key] || ''
    if (!val.trim()) return
    updateQuestion(problemId, q.id, { upgradedAnswer: val, finalFeedback: '', tails: [] })
    setUpgradedAnswers(p => ({ ...p, [key]: '' }))
    setEditingStep3(p => ({ ...p, [key]: false }))
    setRecordings(p => ({ ...p, [`${key}-up`]: false }))
  }

  const submitTail = (problemId: number, q: any, tailIdx: number) => {
    const key = `${problemId}-${q.id}-tail-${tailIdx}`
    const val = tailAnswers[key] || ''
    if (!val.trim()) return
    const newTails = [...(q.tails || [])].map((t: any, i: number) =>
      i === tailIdx ? { ...t, answer: val } : t
    )
    updateQuestion(problemId, q.id, { tails: newTails })
    setTailAnswers(p => ({ ...p, [key]: '' }))
    setRecordings(p => ({ ...p, [key]: false }))
  }

  const SchoolLogo = ({ school, size = 48 }: { school: any; size?: number }) => (
    <div style={{ width: size, height: size, borderRadius: '50%', overflow: 'hidden', background: school.bg, border: `1px solid ${school.color}30`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
      {school.logo ? (
        <img src={school.logo} alt={school.name}
          style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
      ) : (
        <span style={{ color: school.color, fontWeight: 700, fontSize: size * 0.35 }}>
          {(school.shortName || school.name)[0]}
        </span>
      )}
    </div>
  )

  if (step === 'school') {
    return (
      <div style={{ padding: '28px 32px' }}>
        <div style={{ fontSize: 18, fontWeight: 500, color: '#1a1a1a', marginBottom: 4 }}>SKY·교대 제시문 면접</div>
        <div style={{ background: 'linear-gradient(135deg, #3B5BDB, #6366F1)', borderRadius: 14, padding: '24px 28px', marginBottom: 28, marginTop: 16, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <div>
            <div style={{ fontSize: 20, fontWeight: 700, color: '#fff', marginBottom: 6 }}>합격을 노리는 최상위권 학생들을 위해!</div>
            <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.85)' }}>최근 9개년 기출을 분석한 맞춤형 문제로 실전 같은 제시문 면접을 경험하세요.</div>
          </div>
          <div style={{ fontSize: 48 }}>🎓</div>
        </div>

        <div style={{ fontSize: 14, fontWeight: 500, color: '#1a1a1a', marginBottom: 14 }}>학교 선택하기</div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, minmax(0,1fr))', gap: 14 }}>
          {SKY_SCHOOLS.map(s => (
            <div key={s.id} onClick={() => { setSelSchool(s); setSelTrack(null); setShowTrackModal(true) }}
              style={{ background: s.bg, border: `1px solid ${s.color}30`, borderRadius: 14, padding: '28px 20px', textAlign: 'center', cursor: 'pointer' }}>
              <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 14 }}><SchoolLogo school={s} size={64} /></div>
              <div style={{ fontSize: 15, fontWeight: 700, color: s.color, marginBottom: 12 }}>{s.name}</div>
              <button style={{ padding: '7px 20px', background: '#fff', color: s.color, border: `1px solid ${s.color}`, borderRadius: 8, fontSize: 13, fontWeight: 500, cursor: 'pointer', fontFamily: 'inherit' }}>선택하기</button>
            </div>
          ))}
          <div onClick={() => setShowEduModal(true)}
            style={{ background: '#ECFDF5', border: '1px solid #6EE7B730', borderRadius: 14, padding: '28px 20px', textAlign: 'center', cursor: 'pointer' }}>
            <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 14 }}>
              <div style={{ width: 64, height: 64, borderRadius: '50%', overflow: 'hidden', background: '#ECFDF5', border: '1px solid #065F4630', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <img src={EDU_LOGO} alt="교육대학교" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
              </div>
            </div>
            <div style={{ fontSize: 15, fontWeight: 700, color: '#065F46', marginBottom: 12 }}>교육대학교</div>
            <button style={{ padding: '7px 20px', background: '#fff', color: '#065F46', border: '1px solid #065F46', borderRadius: 8, fontSize: 13, fontWeight: 500, cursor: 'pointer', fontFamily: 'inherit' }}>선택하기</button>
          </div>
        </div>

        {showEduModal && (
          <div onClick={() => setShowEduModal(false)} style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', zIndex: 200, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: 16, padding: 28, width: 520, maxHeight: '80vh', overflowY: 'auto' }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
                <div style={{ fontSize: 16, fontWeight: 600 }}>교육대학교 선택</div>
                <div onClick={() => setShowEduModal(false)} style={{ cursor: 'pointer', color: '#6B7280', fontSize: 18 }}>✕</div>
              </div>
              <div style={{ background: '#ECFDF5', border: '0.5px solid #6EE7B7', borderRadius: 10, padding: '10px 14px', fontSize: 12, color: '#065F46', marginBottom: 20, lineHeight: 1.6 }}>
                💡 교대 제시문 면접은 <strong>교직적성·인성 면접</strong>으로, 학교를 선택하면 바로 문제 목록으로 이동합니다.
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, minmax(0,1fr))', gap: 10 }}>
                {EDUCATION_SCHOOLS.map(s => (
                  <div key={s.id} onClick={() => { setSelSchool(s); setShowEduModal(false); setStep('list') }}
                    style={{ background: s.bg, border: `1px solid ${s.color}30`, borderRadius: 12, padding: '16px 12px', textAlign: 'center', cursor: 'pointer' }}
                    onMouseEnter={e => (e.currentTarget.style.boxShadow = `0 4px 12px ${s.color}25`)}
                    onMouseLeave={e => (e.currentTarget.style.boxShadow = 'none')}>
                    <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 8 }}><SchoolLogo school={s} size={44} /></div>
                    <div style={{ fontSize: 12, fontWeight: 700, color: s.color }}>{s.shortName}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {showTrackModal && (
          <div onClick={() => setShowTrackModal(false)} style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', zIndex: 200, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: 16, padding: 28, width: 480 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
                <div style={{ fontSize: 16, fontWeight: 500 }}>계열 선택</div>
                <div onClick={() => setShowTrackModal(false)} style={{ cursor: 'pointer', color: '#6B7280', fontSize: 18 }}>✕</div>
              </div>
              <div style={{ background: '#EEF2FF', borderRadius: 10, padding: '12px 14px', fontSize: 13, color: '#3B5BDB', lineHeight: 1.6, marginBottom: 20 }}>
                SKY 면접과 유사한 <strong>제시문 기반 면접 문제</strong>를 풀어보는 시간이에요!<br />전공과 관련된 계열을 골라야 문제를 만들 수 있어요.
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginBottom: 20 }}>
                {(selSchool?.id === 1 ? TRACKS_SNU : TRACKS_SKY).map(t => (
                  <div key={t.id} onClick={() => setSelTrack(t)}
                    style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '14px 16px', border: `1.5px solid ${selTrack?.id === t.id ? '#3B5BDB' : '#E5E7EB'}`, borderRadius: 10, cursor: 'pointer', background: selTrack?.id === t.id ? '#EEF2FF' : '#fff' }}>
                    <div style={{ fontSize: 24 }}>{t.icon}</div>
                    <div>
                      <div style={{ fontSize: 14, fontWeight: 500 }}>{t.name}</div>
                      <div style={{ fontSize: 11, color: '#6B7280' }}>{t.sub}</div>
                    </div>
                    {selTrack?.id === t.id && (
                      <div style={{ marginLeft: 'auto', width: 20, height: 20, borderRadius: '50%', background: '#3B5BDB', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: 11 }}>✓</div>
                    )}
                  </div>
                ))}
              </div>
              <button onClick={() => { if (selTrack) { setShowTrackModal(false); setStep('list') } }}
                style={{ width: '100%', height: 44, background: selTrack ? '#3B5BDB' : '#E5E7EB', color: selTrack ? '#fff' : '#9CA3AF', border: 'none', borderRadius: 10, fontSize: 14, fontWeight: 500, cursor: selTrack ? 'pointer' : 'not-allowed', fontFamily: 'inherit' }}>
                확인
              </button>
            </div>
          </div>
        )}
      </div>
    )
  }

  if (step === 'list') {
    return (
      <div style={{ padding: '28px 32px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 20 }}>
          <div onClick={() => { setStep('school'); setSelTrack(null); setSelSchool(null) }}
            style={{ width: 32, height: 32, borderRadius: 8, background: '#fff', border: '0.5px solid #E5E7EB', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', fontSize: 14, color: '#6B7280' }}>←</div>
          <div style={{ fontSize: 16, fontWeight: 500 }}>SKY·교대 제시문 면접</div>
        </div>
        <div style={{ background: accentBg, border: `0.5px solid ${accentBorder}`, borderRadius: 12, padding: '16px 20px', marginBottom: 20, display: 'flex', alignItems: 'center', gap: 14 }}>
          <SchoolLogo school={selSchool} size={48} />
          <div>
            <div style={{ fontSize: 16, fontWeight: 700 }}>{selYear}년 {selSchool?.name} {isEdu ? '' : `${selTrack?.name} 계열`}</div>
            <div style={{ fontSize: 12, color: '#6B7280', marginTop: 2 }}>{isEdu ? '교직적성·인성 면접' : selTrack?.sub}</div>
          </div>
        </div>
        <div style={{ display: 'flex', gap: 8, marginBottom: 20, overflowX: 'auto', paddingBottom: 4 }}>
          {YEARS.map(y => (
            <div key={y} onClick={() => setSelYear(y)}
              style={{ padding: '6px 14px', borderRadius: 99, fontSize: 13, cursor: 'pointer', background: selYear === y ? accentColor : '#fff', color: selYear === y ? '#fff' : '#6B7280', border: `0.5px solid ${selYear === y ? accentColor : '#E5E7EB'}`, whiteSpace: 'nowrap' as const }}>
              {y}
            </div>
          ))}
        </div>
        <div style={{ fontSize: 13, color: '#6B7280', marginBottom: 14 }}>총 {curProblems.length}문제</div>
        {curProblems.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px 0', color: '#9CA3AF' }}>
            <div style={{ fontSize: 36, marginBottom: 12 }}>📄</div>
            <div style={{ fontSize: 14 }}>해당 연도의 문제가 없어요.</div>
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, minmax(0,1fr))', gap: 14 }}>
            {curProblems.map((p: any) => {
              const status = getProblemStatus(p)
              return (
                <div key={p.id} style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 12, padding: '20px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 14 }}>
                    <div style={{ width: 40, height: 40, borderRadius: '50%', background: status === 'done' ? '#ECFDF5' : status === 'doing' ? '#FFF3E8' : '#F3F4F6', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18 }}>
                      {status === 'done' ? '✅' : status === 'doing' ? '📝' : '💡'}
                    </div>
                    <div>
                      <div style={{ fontSize: 15, fontWeight: 500 }}>{p.title}</div>
                      <div style={{ fontSize: 11, color: '#6B7280' }}>총 {p.totalQ}문항 | {p.subject}</div>
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button onClick={() => { setSelProblem(p); setStep('solve') }}
                      style={{ flex: 1, height: 38, background: status === 'done' ? '#059669' : status === 'doing' ? '#F97316' : accentColor, color: '#fff', border: 'none', borderRadius: 8, fontSize: 13, fontWeight: 500, cursor: 'pointer', fontFamily: 'inherit' }}>
                      {status === 'done' ? '다시 풀기' : status === 'doing' ? '이어서 풀기' : '문제 풀기'}
                    </button>
                    <button style={{ flex: 1, height: 38, background: '#fff', color: '#6B7280', border: '0.5px solid #E5E7EB', borderRadius: 8, fontSize: 13, cursor: 'pointer', fontFamily: 'inherit' }}>피드백 확인</button>
                  </div>
                </div>
              )
            })}
          </div>
        )}
      </div>
    )
  }

  if (step === 'solve' && selProblem) {
    return (
      <div ref={containerRef} onMouseMove={handleDragMove} onMouseUp={handleDragEnd} onMouseLeave={handleDragEnd}
        style={{ display: 'flex', flexDirection: 'column', height: 'calc(100vh - 50px)', overflow: 'hidden' }}>

        <div style={{ height: 48, background: '#fff', borderBottom: '0.5px solid #E5E7EB', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 24px', flexShrink: 0 }}>
          <div onClick={() => setStep('list')} style={{ fontSize: 13, color: '#6B7280', cursor: 'pointer' }}>← 목록으로</div>
          <div style={{ fontSize: 13, fontWeight: 500 }}>{selYear}학년도 {selSchool?.shortName || selSchool?.name} {isEdu ? '교직적성' : selTrack?.name} · {selProblem.title}</div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <SchoolLogo school={selSchool} size={24} />
            <span style={{ fontSize: 12, color: '#6B7280' }}>{selSchool?.shortName || selSchool?.name}</span>
          </div>
        </div>

        <div style={{ display: 'flex', flex: 1, overflow: 'hidden' }}>
          <div style={{ width: `${leftWidth}%`, borderRight: '0.5px solid #E5E7EB', overflowY: 'auto', padding: '20px 24px', background: '#FAFAFA', flexShrink: 0 }}>
            <div style={{ fontSize: 11, fontWeight: 500, color: '#9CA3AF', marginBottom: 10, letterSpacing: 1 }}>제시문</div>
            {selProblem.pdfUrl
              ? <embed src={selProblem.pdfUrl} type="application/pdf" width="100%" style={{ minHeight: 600, borderRadius: 8 }} />
              : <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 10, padding: '20px 24px', fontSize: 14, color: '#1a1a1a', lineHeight: 2, whiteSpace: 'pre-line' as const, fontFamily: 'Georgia, serif' }}>{selProblem.pdfMock}</div>
            }
          </div>

          <div onMouseDown={handleDragStart}
            style={{ width: 6, background: '#E5E7EB', cursor: 'col-resize', flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
            onMouseEnter={e => (e.currentTarget.style.background = accentBorder)}
            onMouseLeave={e => { if (!isDragging.current) e.currentTarget.style.background = '#E5E7EB' }}>
            <div style={{ width: 2, height: 40, background: '#9CA3AF', borderRadius: 99 }} />
          </div>

          <div style={{ flex: 1, overflowY: 'auto', padding: '20px', display: 'flex', flexDirection: 'column', gap: 32 }}>
            {selProblem.questions.map((q: any, qi: number) => {
              const qKey = `${selProblem.id}-${q.id}`
              const qStep = getQStep(q)

              return (
                <div key={q.id} style={{ borderBottom: qi < selProblem.questions.length - 1 ? '1px solid #F3F4F6' : 'none', paddingBottom: qi < selProblem.questions.length - 1 ? 32 : 0 }}>
                  <div style={{ background: accentBg, border: `0.5px solid ${accentBorder}`, borderRadius: 10, padding: '12px 14px', marginBottom: 10 }}>
                    <div style={{ fontSize: 11, fontWeight: 500, color: accentColor, marginBottom: 4 }}>문제 {qi + 1}.</div>
                    <div style={{ fontSize: 13, fontWeight: 500, lineHeight: 1.7 }}>{q.text}</div>
                  </div>

                  <div style={{ display: 'flex', alignItems: 'flex-start', marginBottom: 16 }}>
                    {STEP_LABELS.map((label, i) => {
                      const stepNum = i + 1
                      const isDone = stepNum < qStep
                      const isOn = stepNum === qStep
                      return (
                        <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4, position: 'relative' }}>
                          {i < STEP_LABELS.length - 1 && (
                            <div style={{ position: 'absolute', top: 11, left: '55%', width: '90%', height: 2, background: isDone ? '#059669' : '#E5E7EB', zIndex: 0 }} />
                          )}
                          <div style={{ width: 22, height: 22, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 10, fontWeight: 600, zIndex: 1, position: 'relative', background: isDone ? '#059669' : isOn ? accentColor : '#F3F4F6', color: isDone || isOn ? '#fff' : '#9CA3AF', border: `2px solid ${isDone ? '#059669' : isOn ? accentColor : '#E5E7EB'}` }}>
                            {isDone ? '✓' : stepNum}
                          </div>
                          <div style={{ fontSize: 10, color: isDone ? '#059669' : isOn ? accentColor : '#9CA3AF', fontWeight: isOn ? 600 : 400, whiteSpace: 'nowrap' as const }}>{label}</div>
                        </div>
                      )
                    })}
                  </div>

                  <div style={{ marginBottom: 12 }}>
                    <div onClick={() => setOpenIntents(p => ({ ...p, [qKey]: !p[qKey] }))}
                      style={{ display: 'flex', alignItems: 'center', gap: 6, cursor: 'pointer', padding: '6px 10px', background: openIntents[qKey] ? '#FFF3E8' : '#F8F7F5', borderRadius: 7, border: `0.5px solid ${openIntents[qKey] ? '#FDBA74' : '#E5E7EB'}` }}>
                      <span style={{ fontSize: 11, color: openIntents[qKey] ? '#D97706' : '#6B7280', fontWeight: 500 }}>💡 질문 의도 파악</span>
                      <span style={{ marginLeft: 'auto', fontSize: 10, color: '#9CA3AF' }}>{openIntents[qKey] ? '▲' : '▼'}</span>
                    </div>
                    {openIntents[qKey] && (
                      <div style={{ background: '#FFF8F0', border: '0.5px solid #FDBA74', borderRadius: '0 0 8px 8px', padding: '10px 12px' }}>
                        <ul style={{ paddingLeft: 16, margin: 0 }}>
                          {(q.intent || []).map((item: string, idx: number) => (
                            <li key={idx} style={{ fontSize: 12, color: '#92400E', lineHeight: 1.7 }}>{item}</li>
                          ))}
                        </ul>
                      </div>
                    )}
                  </div>

                  <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 10, padding: '12px 14px', marginBottom: 10 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 8 }}>
                      <span style={{ fontSize: 10, fontWeight: 700, color: '#fff', background: qStep > 1 ? '#059669' : '#6B7280', padding: '2px 8px', borderRadius: 99 }}>Step 1</span>
                      <span style={{ fontSize: 11, color: '#6B7280' }}>내 첫 답변</span>
                    </div>
                    {q.answer && !editingStep1[qKey] ? (
                      <div>
                        <div style={{ background: '#F8F7F5', borderRadius: 8, padding: '10px 12px', fontSize: 13, color: '#374151', lineHeight: 1.8, marginBottom: 8 }}>{q.answer}</div>
                        <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                          <button onClick={() => { setEditingStep1(p => ({ ...p, [qKey]: true })); setAnswers(p => ({ ...p, [qKey]: q.answer })) }}
                            style={{ fontSize: 11, color: '#6B7280', background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 6, padding: '4px 10px', cursor: 'pointer', fontFamily: 'inherit' }}>✏️ 수정</button>
                        </div>
                      </div>
                    ) : (
                      <>
                        {recordings[qKey] && (
                          <div style={{ background: '#FEE2E2', border: '0.5px solid #FCA5A5', borderRadius: 8, padding: '8px 12px', marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
                            <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#EF4444' }} />
                            <span style={{ fontSize: 12, color: '#DC2626', fontWeight: 500 }}>녹음 중...</span>
                          </div>
                        )}
                        <textarea value={answers[qKey] || ''} onChange={e => setAnswers(p => ({ ...p, [qKey]: e.target.value }))}
                          placeholder="답변을 작성하거나 마이크로 녹음해주세요..." rows={4}
                          style={{ width: '100%', border: '0.5px solid #E5E7EB', borderRadius: 8, padding: '10px 12px', fontSize: 13, outline: 'none', resize: 'vertical' as const, fontFamily: 'inherit', lineHeight: 1.7, boxSizing: 'border-box' as const }} />
                        <div style={{ display: 'flex', gap: 8, marginTop: 8, justifyContent: 'flex-end' }}>
                          {editingStep1[qKey] && (
                            <button onClick={() => { setEditingStep1(p => ({ ...p, [qKey]: false })); setAnswers(p => ({ ...p, [qKey]: '' })) }}
                              style={{ height: 36, padding: '0 12px', background: '#fff', color: '#6B7280', border: '0.5px solid #E5E7EB', borderRadius: 7, fontSize: 12, cursor: 'pointer', fontFamily: 'inherit' }}>취소</button>
                          )}
                          <MicBtn recording={recordings[qKey] || false} onClick={() => setRecordings(p => ({ ...p, [qKey]: !p[qKey] }))} />
                          <SubmitBtn label={editingStep1[qKey] ? '수정 완료' : '답변 제출'} onClick={() => submitAnswer(selProblem.id, q)} disabled={!(answers[qKey] || '').trim()} />
                        </div>
                      </>
                    )}
                  </div>

                  {q.answer && (
                    <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 10, padding: '12px 14px', marginBottom: 10 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 8 }}>
                        <span style={{ fontSize: 10, fontWeight: 700, color: '#fff', background: qStep > 2 ? '#059669' : accentColor, padding: '2px 8px', borderRadius: 99 }}>Step 2</span>
                        <span style={{ fontSize: 11, color: '#6B7280' }}>선생님 1차 피드백</span>
                      </div>
                      {q.teacherFeedback
                        ? <div style={{ background: accentBg, border: `0.5px solid ${accentBorder}`, borderRadius: 8, padding: '10px 12px', fontSize: 13, color: '#1E3A8A', lineHeight: 1.8 }}>{q.teacherFeedback}</div>
                        : <div style={{ background: '#F8F7F5', borderRadius: 8, padding: '10px 12px', fontSize: 12, color: '#9CA3AF', textAlign: 'center' as const }}>선생님 피드백을 기다리는 중이에요 ✏️</div>
                      }
                    </div>
                  )}

                  {q.teacherFeedback && (
                    <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 10, padding: '12px 14px', marginBottom: 10 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 8 }}>
                        <span style={{ fontSize: 10, fontWeight: 700, color: '#fff', background: qStep > 3 ? '#059669' : '#6B7280', padding: '2px 8px', borderRadius: 99 }}>Step 3</span>
                        <span style={{ fontSize: 11, color: '#6B7280' }}>업그레이드 답변</span>
                      </div>
                      {q.upgradedAnswer && !editingStep3[qKey] ? (
                        <div>
                          <div style={{ background: '#F8F7F5', borderRadius: 8, padding: '10px 12px', fontSize: 13, color: '#374151', lineHeight: 1.8, marginBottom: 8 }}>{q.upgradedAnswer}</div>
                          <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                            <button onClick={() => { setEditingStep3(p => ({ ...p, [qKey]: true })); setUpgradedAnswers(p => ({ ...p, [qKey]: q.upgradedAnswer })) }}
                              style={{ fontSize: 11, color: '#6B7280', background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 6, padding: '4px 10px', cursor: 'pointer', fontFamily: 'inherit' }}>✏️ 수정</button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <div style={{ background: '#FFF3E8', border: '0.5px solid #FDBA74', borderRadius: 8, padding: '8px 12px', fontSize: 12, color: '#92400E', marginBottom: 8 }}>
                            💡 선생님 피드백을 반영해서 답변을 업그레이드해보세요!
                          </div>
                          {recordings[`${qKey}-up`] && (
                            <div style={{ background: '#FEE2E2', border: '0.5px solid #FCA5A5', borderRadius: 8, padding: '8px 12px', marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
                              <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#EF4444' }} />
                              <span style={{ fontSize: 12, color: '#DC2626', fontWeight: 500 }}>녹음 중...</span>
                            </div>
                          )}
                          <textarea value={upgradedAnswers[qKey] || ''} onChange={e => setUpgradedAnswers(p => ({ ...p, [qKey]: e.target.value }))}
                            placeholder="피드백을 반영한 업그레이드 답변을 작성하거나 마이크로 녹음해주세요..." rows={4}
                            style={{ width: '100%', border: '0.5px solid #E5E7EB', borderRadius: 8, padding: '10px 12px', fontSize: 13, outline: 'none', resize: 'vertical' as const, fontFamily: 'inherit', lineHeight: 1.7, boxSizing: 'border-box' as const }} />
                          <div style={{ display: 'flex', gap: 8, marginTop: 8, justifyContent: 'flex-end' }}>
                            {editingStep3[qKey] && (
                              <button onClick={() => { setEditingStep3(p => ({ ...p, [qKey]: false })); setUpgradedAnswers(p => ({ ...p, [qKey]: '' })) }}
                                style={{ height: 36, padding: '0 12px', background: '#fff', color: '#6B7280', border: '0.5px solid #E5E7EB', borderRadius: 7, fontSize: 12, cursor: 'pointer', fontFamily: 'inherit' }}>취소</button>
                            )}
                            <MicBtn recording={recordings[`${qKey}-up`] || false} onClick={() => setRecordings(p => ({ ...p, [`${qKey}-up`]: !p[`${qKey}-up`] }))} />
                            <SubmitBtn label={editingStep3[qKey] ? '수정 완료' : '업그레이드 제출'} onClick={() => submitUpgrade(selProblem.id, q)} disabled={!(upgradedAnswers[qKey] || '').trim()} />
                          </div>
                        </>
                      )}
                    </div>
                  )}

                  {q.upgradedAnswer && (
                    <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 10, padding: '12px 14px', marginBottom: 10 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 8 }}>
                        <span style={{ fontSize: 10, fontWeight: 700, color: '#fff', background: '#059669', padding: '2px 8px', borderRadius: 99 }}>Step 4</span>
                        <span style={{ fontSize: 11, color: '#6B7280' }}>선생님 최종 피드백</span>
                      </div>
                      {q.finalFeedback
                        ? <div style={{ background: '#ECFDF5', border: '0.5px solid #6EE7B7', borderRadius: 8, padding: '10px 12px', fontSize: 13, color: '#065F46', lineHeight: 1.8 }}>{q.finalFeedback}</div>
                        : <div style={{ background: '#F8F7F5', borderRadius: 8, padding: '10px 12px', fontSize: 12, color: '#9CA3AF', textAlign: 'center' as const }}>선생님 최종 피드백을 기다리는 중이에요 ✏️</div>
                      }
                    </div>
                  )}

                  {q.finalFeedback && q.tails && q.tails.length > 0 && (
                    <div style={{ background: '#fff', border: '0.5px solid #E5E7EB', borderRadius: 10, padding: '12px 14px' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 12 }}>
                        <span style={{ fontSize: 10, fontWeight: 700, color: '#fff', background: '#3B5BDB', padding: '2px 8px', borderRadius: 99 }}>Step 5</span>
                        <span style={{ fontSize: 11, color: '#6B7280' }}>꼬리질문</span>
                      </div>
                      {q.tails.map((tail: any, ti: number) => {
                        const tailKey = `${qKey}-tail-${ti}`
                        return (
                          <div key={ti} style={{ marginBottom: ti < q.tails.length - 1 ? 16 : 0 }}>
                            <div style={{ display: 'flex', alignItems: 'flex-start', gap: 7, padding: '8px 10px', background: '#F8F7F5', borderRadius: 7, marginBottom: 8, fontSize: 12, color: '#374151', lineHeight: 1.5 }}>
                              <span style={{ fontSize: 10, fontWeight: 500, color: '#3B5BDB', background: '#EEF2FF', padding: '2px 6px', borderRadius: 99, flexShrink: 0, marginTop: 1 }}>꼬리 {ti + 1}</span>
                              {typeof tail === 'string' ? tail : tail.text}
                            </div>
                            {recordings[tailKey] && (
                              <div style={{ background: '#FEE2E2', border: '0.5px solid #FCA5A5', borderRadius: 8, padding: '8px 12px', marginBottom: 6, display: 'flex', alignItems: 'center', gap: 8 }}>
                                <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#EF4444' }} />
                                <span style={{ fontSize: 12, color: '#DC2626', fontWeight: 500 }}>녹음 중...</span>
                              </div>
                            )}
                            {tail.answer ? (
                              <div style={{ background: '#F8F7F5', borderRadius: 8, padding: '10px 12px', fontSize: 13, color: '#374151', lineHeight: 1.8 }}>{tail.answer}</div>
                            ) : (
                              <div style={{ background: '#F8F7F5', borderRadius: 8, padding: '10px 12px' }}>
                                <textarea value={tailAnswers[tailKey] || ''} onChange={e => setTailAnswers(p => ({ ...p, [tailKey]: e.target.value }))}
                                  placeholder="꼬리질문에 대한 답변을 작성하거나 마이크로 녹음해주세요..." rows={2}
                                  style={{ width: '100%', border: '0.5px solid #E5E7EB', borderRadius: 7, padding: '8px 10px', fontSize: 12, outline: 'none', resize: 'none' as const, fontFamily: 'inherit', lineHeight: 1.6, background: '#fff', boxSizing: 'border-box' as const }} />
                                <div style={{ display: 'flex', gap: 8, marginTop: 8, justifyContent: 'flex-end' }}>
                                  <MicBtn recording={recordings[tailKey] || false} onClick={() => setRecordings(p => ({ ...p, [tailKey]: !p[tailKey] }))} />
                                  <button onClick={() => submitTail(selProblem.id, q, ti)} disabled={!(tailAnswers[tailKey] || '').trim()}
                                    style={{ height: 34, padding: '0 14px', background: (tailAnswers[tailKey] || '').trim() ? '#3B5BDB' : '#E5E7EB', color: (tailAnswers[tailKey] || '').trim() ? '#fff' : '#9CA3AF', border: 'none', borderRadius: 7, fontSize: 12, fontWeight: 500, cursor: (tailAnswers[tailKey] || '').trim() ? 'pointer' : 'not-allowed', fontFamily: 'inherit' }}>제출</button>
                                </div>
                              </div>
                            )}
                          </div>
                        )
                      })}
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        </div>
      </div>
    )
  }

  return null
}
